// ================================================
//  EDIT THIS NODE -- all your settings live here
// ================================================

var AGENCY_NAME         = 'Your Agency Name';
var GHL_API_KEY         = 'YOUR_GHL_API_KEY';
var GHL_LOCATION_ID     = 'YOUR_GHL_LOCATION_ID';
var ACCOUNT_MANAGER     = 'Your Account Manager Name';
var ACCOUNT_MANAGER_ID  = 'YOUR_GHL_USER_ID';
var SLACK_CHANNEL       = 'YOUR_SLACK_CHANNEL_ID';
var CALENDAR_ID         = 'YOUR_GOOGLE_CALENDAR_ID';
var DRIVE_PARENT_FOLDER = 'YOUR_GOOGLE_DRIVE_PARENT_FOLDER_ID';
var LOG_SHEET_ID        = 'YOUR_LOG_SHEET_ID';
var LOG_SHEET_NAME      = 'Onboarding Log';
var BOOKING_LINK        = 'YOUR_BOOKING_LINK';

// ================================================
//  DO NOT EDIT BELOW THIS LINE
// ================================================

var body = $input.first().json.body || $input.first().json;
var contact     = body.contact || body.Contact || {};
var opportunity = body.opportunity || body.Opportunity || body;

var clientName    = contact.name || contact.fullName || opportunity.contactName || '';
var clientEmail   = contact.email || opportunity.contactEmail || '';
var clientPhone   = contact.phone || contact.phoneRaw || '';
var clientCompany = contact.companyName || contact.company || '';
var contactId     = contact.id || opportunity.contactId || '';
var opportunityId = opportunity.id || opportunity.opportunityId || '';
var dealValue     = opportunity.monetaryValue || opportunity.value || 0;
var serviceName   = opportunity.name || opportunity.opportunityName || 'Service Package';
var dealNotes     = opportunity.notes || opportunity.description || 'none';

// Calculate kickoff -- 2 business days from now
var now = new Date();
var kickoff = new Date(now);
var daysAdded = 0;
while (daysAdded < 2) {
  kickoff.setDate(kickoff.getDate() + 1);
  var day = kickoff.getDay();
  if (day !== 0 && day !== 6) daysAdded++;
}
kickoff.setHours(10, 0, 0, 0);
var kickoffEnd = new Date(kickoff);
kickoffEnd.setHours(11, 0, 0, 0);

return [{
  json: {
    agency_name:          AGENCY_NAME,
    ghl_api_key:          GHL_API_KEY,
    ghl_location_id:      GHL_LOCATION_ID,
    account_manager:      ACCOUNT_MANAGER,
    account_manager_id:   ACCOUNT_MANAGER_ID,
    slack_channel:        SLACK_CHANNEL,
    calendar_id:          CALENDAR_ID,
    drive_parent_folder:  DRIVE_PARENT_FOLDER,
    log_sheet_id:         LOG_SHEET_ID,
    log_sheet_name:       LOG_SHEET_NAME,
    booking_link:         BOOKING_LINK,
    client_name:          clientName,
    client_email:         clientEmail,
    client_phone:         clientPhone,
    client_company:       clientCompany,
    contact_id:           contactId,
    opportunity_id:       opportunityId,
    deal_value:           dealValue,
    service_name:         serviceName,
    deal_notes:           dealNotes,
    kickoff_start:        kickoff.toISOString(),
    kickoff_end:          kickoffEnd.toISOString(),
    timestamp:            now.toISOString(),
    folder_name:          clientName + ' - ' + serviceName + ' - ' + now.toISOString().split('T')[0]
  }
}];

parameters.text:
=You are an expert client onboarding specialist for a digital agency called {{ $json.agency_name }}.

A new client just signed. Generate their complete onboarding plan. Return ONLY a valid JSON object -- no markdown, no explanation, no extra text.

CLIENT DETAILS:
Name: {{ $json.client_name }}
Company: {{ $json.client_company }}
Service purchased: {{ $json.service_name }}
Deal value: {{ $json.deal_value }}
Deal notes: {{ $json.deal_notes }}
Account manager: {{ $json.account_manager }}
Booking link: {{ $json.booking_link }}

Generate this exact JSON structure:

{"welcome_subject":"Short plain-text email subject line, no emojis","welcome_email":"Full plain-text welcome email body. Warm, professional, excited. Mention the service they purchased. Include the booking link naturally. Sign off from the account manager. No HTML. No emojis. 150-200 words.","client_summary":"2-sentence internal summary of who this client is and what they need -- for the Slack team alert","tasks":[{"title":"Task title -- short and action-oriented","description":"One sentence explaining what needs to be done and why","due_days":1}]}

TASK RULES:
- Generate exactly 6 tasks specific to the service purchased
- due_days is how many days from today (use 1, 3, 5, 7, 14, 30)
- Tasks should cover: internal setup, client access provisioning, first deliverable, check-in call, mid-point review, 30-day debrief
- Make tasks specific to the service -- not generic placeholders
- All task titles and descriptions must be plain text, no emojis, no special characters

parameters.jsCode:
var text = $input.first().json.text || '';
var cfg  = $('Configure Settings').first().json;

var defaultTasks = [
  { title: 'Send onboarding questionnaire', description: 'Send the standard onboarding questionnaire to gather assets and access details', due_days: 1 },
  { title: 'Set up client workspace', description: 'Create all internal tools, folders, and access for the new client', due_days: 3 },
  { title: 'Kickoff call preparation', description: 'Prepare kickoff agenda and share with client', due_days: 5 },
  { title: 'Deliver first milestone', description: 'Complete and deliver the first agreed deliverable', due_days: 7 },
  { title: 'Mid-point check-in', description: 'Run a 2-week check-in call to review progress', due_days: 14 },
  { title: '30-day results review', description: 'Run a 30-day review to assess results and plan next steps', due_days: 30 }
];

var parsed = {
  welcome_subject: 'Welcome to ' + cfg.agency_name,
  welcome_email: 'Hi ' + cfg.client_name + ', welcome aboard! We are so excited to work with you. Your account manager ' + cfg.account_manager + ' will be in touch shortly. You can also book time here: ' + cfg.booking_link,
  client_summary: cfg.client_name + ' signed for ' + cfg.service_name + '. Deal value: ' + cfg.deal_value + '.',
  tasks: defaultTasks
};

try {
  var match = text.match(/\{[\s\S]*\}/);
  if (match) {
    var attempt = JSON.parse(match[0]);
    if (attempt.tasks && attempt.tasks.length > 0) parsed = attempt;
  }
} catch (e) {}

if (!parsed.tasks || parsed.tasks.length === 0) parsed.tasks = defaultTasks;

var now = new Date();

return parsed.tasks.map(function(task, i) {
  var dueDate = new Date(now);
  dueDate.setDate(dueDate.getDate() + (task.due_days || (i + 1) * 5));
  return {
    json: Object.assign({}, cfg, {
      welcome_subject:  parsed.welcome_subject,
      welcome_email:    parsed.welcome_email,
      client_summary:   parsed.client_summary,
      all_tasks:        parsed.tasks,
      task_title:       task.title,
      task_description: task.description,
      task_due_date:    dueDate.toISOString().split('T')[0],
      task_index:       i,
      total_tasks:      parsed.tasks.length
    })
  };
});

var items = $input.all();
var first = items[0].json;

var taskLines = first.all_tasks ? first.all_tasks.slice(0, 3).map(function(t, i) {
  return (i + 1) + '. ' + t.title + ' (day ' + t.due_days + ')';
}).join('\n') : 'Tasks created in GHL';

return [{ json: Object.assign({}, first, {
  tasks_created: items.length,
  task_summary:  taskLines
}) }];
